    const uint32_t Cw = static_cast<uint32_t>(w_shape->GetDim(1));
    const uint32_t R = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t S = static_cast<uint32_t>(w_shape->GetDim(3));

    if (C != Cw) {
        return ge::GRAPH_FAILED;
    }

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *subtract1_value = attrs->GetAttrPointer<float>(0);
    const float *subtract2_value = attrs->GetAttrPointer<float>(1);
    const int32_t *poolK_ptr = attrs->GetAttrPointer<int32_t>(2);
    const uint32_t poolK = static_cast<uint32_t>(*poolK_ptr);

    // Conv params fixed: stride=1, padding=0, dilation=1.
    if (H < R || W < S) {
        return ge::GRAPH_FAILED;
