    const uint32_t OH = H - R + 1u;
    const uint32_t OW = W - S + 1u;

    // AvgPool params: kernel=poolK, stride=poolK, padding=0
    if (OH < poolK || OW < poolK) {
        return ge::GRAPH_FAILED;
    }
    const uint32_t OHP = OH / poolK;
    const uint32_t OWP = OW / poolK;

    const uint32_t totalPooled = N * K * OHP * OWP;

    // Tile selection: compute a modest number of pooled outputs per core per iteration.
